const campaigns = $input.first().json.campaigns || [];
const totalSpend = campaigns.reduce((s, c) => s + (c.spend || 0), 0);
const totalLeads = campaigns.reduce((s, c) => s + (c.leads || 0), 0);
const totalClicks = campaigns.reduce((s, c) => s + (c.clicks || 0), 0);
const totalImpressions = campaigns.reduce((s, c) => s + (c.impressions || 0), 0);
const avgCPL = totalLeads > 0 ? (totalSpend / totalLeads).toFixed(2) : 'N/A';
const avgCTR = totalImpressions > 0 ? ((totalClicks / totalImpressions) * 100).toFixed(2) : '0';

const alerts = [];
campaigns.forEach(c => {
  if (c.cost_per_lead > 5) alerts.push(`⚠️ ${c.campaign_name}: CPA ${c.cost_per_lead}€ (previsok!)`);
  if (c.leads === 0 && c.spend > 10) alerts.push(`🚨 ${c.campaign_name}: ${c.spend}€ potrošeno, 0 leadova`);
  if (c.ctr < 0.5 && c.impressions > 500) alerts.push(`📉 ${c.campaign_name}: CTR ${c.ctr}% (ispod 0.5%)`);
});

const topCampaign = campaigns.filter(c => c.leads > 0).sort((a, b) => a.cost_per_lead - b.cost_per_lead)[0];

return [{
  json: {
    date: $input.first().json.date,
    totalSpend: totalSpend.toFixed(2),
    totalLeads,
    totalClicks,
    totalImpressions,
    avgCPL,
    avgCTR,
    alerts,
    topCampaign: topCampaign ? topCampaign.campaign_name : 'N/A',
    campaigns,
    hasAlerts: alerts.length > 0
  }
}];

